DROP TABLE TEMPLATE CASCADE CONSTRAINTS;CREATE TABLE TEMPLATE(    template_id   RAW(16) DEFAULT SYS_GUID() PRIMARY KEY,    name          VARCHAR2(30)            NOT NULL,    body_html     CLOB                    NOT NULL,    type          VARCHAR2(10)            NOT NULL CHECK (type IN ('BASE', 'ADDED')),    cover_img_url VARCHAR2(500)           Not NULL,    bgm_url       VARCHAR2(500)           NOT NULL,    qr_url        VARCHAR2(500)           NOT NULL,    created_at    DATE    DEFAULT SYSDATE NOT NULL,    updated_at    DATE    DEFAULT SYSDATE NOT NULL);TRUNCATE TABLE TEMPLATE;-- 1. 기본 템플릿 (BASE)INSERT INTO TEMPLATE (name, body_html, type, cover_img_url, bgm_url, qr_url)VALUES ('야경',        '<div class="night-theme"><h3>🌃 밤의 기록</h3><p>{{content}}</p></div>',        'BASE',        'night_cover.png',        'https://music.com/night.mp3',        'qr_default.png');-- 2. 벚꽃 템플릿 (ADDED - QR 전용이라 가정)INSERT INTO TEMPLATE (name, body_html, type, cover_img_url, bgm_url, qr_url)VALUES ('벚꽃',        '<div class="spring-theme"><h3>🌸 벚꽃 엔딩</h3><p>{{content}}</p></div>',        'ADDED',        'cherry_cover.png',        'https://music.com/spring.mp3',        'qr_spring_event.png');-- 3. 레트로 템플릿 (BASE)INSERT INTO TEMPLATE (name, body_html, type, cover_img_url, bgm_url, qr_url)VALUES ('레트로',        '<div class="retro-style"><pre>{{content}}</pre></div>',        'BASE',        'retro_cover.png',        'https://music.com/retro.mp3',        'qr_retro_info.png');SELECT *FROM template;